SELECT species, COUNT(*) AS tree_count
FROM trees
WHERE species = 'Pinus radiata';

SELECT AVG(age_range) AS average_age_range
FROM trees
WHERE location = 'Gujrat' AND vitality = 'Weak';

SELECT AVG(height) AS average_height
FROM trees
WHERE height > 0 AND location = '0' AND vitality = 'Healthy';

SELECT AVG(CAST(REPLACE(height, ' m', '') AS REAL)) AS average_height
FROM trees
WHERE location = 'Gujrat' AND vitality = 'Healthy';
